# ── TV59: TV55 + aggressive 2-agent (align earlier with 2 agents) ──────────

class AlphaTournamentV59AgentPolicy(AlphaTournamentV55AgentPolicy):
    """TournamentV59: TV55 (TV46+TV50) + more aggressive 2-agent play.

    2-agent matches drag tournament scores. TV7's strategy (pure mine until 500,
    then only align at min_res >= 50) is too conservative. TV59 starts aligning
    earlier with 2 agents: step 200 with min_res >= 14.
    """

    def _pressure_budgets(self, state: MettagridState, *, objective: str | None = None) -> tuple[int, int]:
        """TV55 budgets + more aggressive 2-agent play."""
        step = state.step or self._step_index
        min_res = _h.team_min_resource(state)
        can_hearts = _h.team_can_refill_hearts(state)
        num_agents = self.policy_env_info.num_agents

        if objective == "resource_coverage":
            return 0, 0

        if num_agents <= 2:
            # More aggressive: start aligning at step 200 with min_res >= 14
            if step < 200 or (min_res < 7 and not can_hearts):
                return 0, 0
            if min_res >= 14:
                return 1, 0  # One aligner, one miner
            return 0, 0

        # 4+ agents: use parent's budgets
        return super()._pressure_budgets(state, objective=objective)


