# ── TV70: TV61 + smarter 2-agent play ──────────────────────────────────────

class AlphaTournamentV70AgentPolicy(AlphaTournamentV61AgentPolicy):
    """TournamentV70: TV61 + improved 2-agent performance.

    In 2-agent games, we're paired with 6 opponent bots. Our agents are 2 of
    8 on a team. Current TV7 2-agent strategy: both mine for 500 steps, then
    maybe 1 aligner if min_res >= 50. This is too conservative.

    TV70: Start 1 aligner at step 200 (instead of 500) if economy is okay.
    Also: in 2-agent games, idle aligners should always scramble since the
    other 6 bots on our team are likely aligning.
    """

    def _pressure_budgets(self, state: MettagridState, *, objective: str | None = None) -> tuple[int, int]:
        """Less conservative 2-agent play + parent's 5+ agent budgets."""
        step = state.step or self._step_index
        min_res = _h.team_min_resource(state)
        can_hearts = _h.team_can_refill_hearts(state)
        num_agents = self.policy_env_info.num_agents

        if objective == "resource_coverage":
            return 0, 0

        if num_agents <= 2:
            # Less conservative: start 1 aligner at step 200
            if step < 200 or (min_res < 7 and not can_hearts):
                return 0, 0
            # 1 aligner when economy can support it
            if min_res >= 14:
                return 1, 0
            return 0, 0

        # For 4+ agents, use parent's budgets
        return super()._pressure_budgets(state, objective=objective)


class AlphaTournamentV70Policy(MettagridSemanticPolicy):
    """TournamentV70: TV61 + improved 2-agent play."""
    short_names = ["alpha-tournament-v70"]

