# ── TV88: TV82 + TV70's pressure_budgets fix ─────────────────────────────────

class AlphaTournamentV88AgentPolicy(AlphaTournamentV82AgentPolicy):
    """TournamentV88: TV82 + proper 2-agent pressure_budgets from TV70.

    BUG FIX: TV81/TV82 inherit TV7's _pressure_budgets which requires
    min_res >= 50 for 2-agent aligner activation. TV70 lowered this to
    min_res >= 14. TV81 copied TV70's _aligner_action changes but missed
    the _pressure_budgets override. TV88 adds it back.
    """

    def _pressure_budgets(self, state: MettagridState, *, objective: str | None = None) -> tuple[int, int]:
        step = state.step or self._step_index
        min_res = _h.team_min_resource(state)
        can_hearts = _h.team_can_refill_hearts(state)
        num_agents = self.policy_env_info.num_agents

        if objective == "resource_coverage":
            return 0, 0

        if num_agents <= 2:
            # TV70's less conservative 2-agent play
            if step < 200 or (min_res < 7 and not can_hearts):
                return 0, 0
            if min_res >= 14:
                return 1, 0
            return 0, 0

        return super()._pressure_budgets(state, objective=objective)


