# ── TV96: TV95 + more aligners in 4v4 ────────────────────────────────────────

class AlphaTournamentV96AgentPolicy(AlphaTournamentV95AgentPolicy):
    """TournamentV96: TV95 + 3 aligners in 4v4.

    In 4v4 with zero scramblers, we currently run 2 aligners + 2 miners.
    Try 3 aligners + 1 miner for faster junction capture.
    """

    def _pressure_budgets(self, state: MettagridState, *, objective: str | None = None) -> tuple[int, int]:
        step = state.step or self._step_index
        min_res = _h.team_min_resource(state)
        can_hearts = _h.team_can_refill_hearts(state)
        num_agents = self.policy_env_info.num_agents

        if objective == "resource_coverage":
            return 0, 0

        if num_agents <= 2:
            if step < 200 or (min_res < 7 and not can_hearts):
                return 0, 0
            if min_res >= 7:
                return 1, 0
            return 0, 0

        if num_agents <= 4:
            if step < 80:
                return 1, 0
            if min_res < 7:
                return 1, 0
            if min_res < 1 and not can_hearts:
                return 1, 0
            if objective == "economy_bootstrap":
                return 1, 0
            # 3 aligners in 4v4 (leave 1 miner)
            return min(3, num_agents - 1), 0

        # 5+ agents
        return AlphaTournamentV94AgentPolicy._pressure_budgets(self, state, objective=objective)


