# ── TV102: TV90 + 2-agent dual aligner (both agents align when resources allow) ──

class AlphaTournamentV102AgentPolicy(AlphaTournamentV90AgentPolicy):
    """TournamentV102: TV90 + dual aligner in 2-agent mode.

    PROBLEM: In 2v6 games, TV90 assigns 1 aligner + 1 miner. The aligner
    aligns ~4 junctions then loops idle_align_scramble forever. The miner
    accumulates massive resources (300+ of each) that are never used.

    FIX: Once hub has enough resources (min_res >= 20), promote BOTH agents
    to aligners. This doubles alignment capacity and uses stockpiled resources.
    """

    def _pressure_budgets(self, state: MettagridState, *, objective: str | None = None) -> tuple[int, int]:
        step = state.step or self._step_index
        min_res = _h.team_min_resource(state)
        can_hearts = _h.team_can_refill_hearts(state)
        num_agents = self.policy_env_info.num_agents

        if objective == "resource_coverage":
            return 0, 0

        if num_agents <= 2:
            if step < 200 or (min_res < 7 and not can_hearts):
                return 0, 0
            # Once resources are healthy, both agents become aligners
            if min_res >= 20:
                return 2, 0
            if min_res >= 7:
                return 1, 0
            return 0, 0

        return AlphaTournamentV82AgentPolicy._pressure_budgets(self, state, objective=objective)


class AlphaTournamentV102Policy(MettagridSemanticPolicy):
    """TournamentV102: TV90 + dual aligner in 2-agent mode."""
