# ── TV168: TV160 + more aggressive early expansion (faster 6a ramp) ───────────

class AlphaTournamentV168AgentPolicy(AlphaTournamentV160AgentPolicy):
    """TournamentV168: TV160 + faster early expansion for 6a.

    TV160's 6a ramp: step<30->2, then gates on min_res (30->2, 50->3, 100->4+).
    This variant: step 15->2 aligners, and lower first threshold (min_res 20->2).
    Theory: the first 100 steps of alignment are highest-value (most neutrals
    near hub), so getting 2 aligners out 15 steps earlier compounds.
    """

    def _pressure_budgets(self, state: MettagridState, *, objective: str | None = None) -> tuple[int, int]:
        step = state.step or self._step_index
        min_res = _h.team_min_resource(state)
        can_hearts = _h.team_can_refill_hearts(state)
        num_agents = self.policy_env_info.num_agents
        team_size = len(self._shared_team_ids) if self._shared_team_ids else num_agents

        if objective == "resource_coverage":
            return 0, 0

        # 2-agent: same as TV160/TV142
        if team_size <= 2:
            if not can_hearts and min_res < 7:
                return 1, 0
            return 2, 0

        # 4-agent: same as TV160/TV142
        if team_size <= 4:
            if step < 50:
                return 1, 0
            if min_res < 7 and not can_hearts:
                return 1, 0
            if min_res < 20:
                return 1, 0
            aligner_budget = 2
            if min_res >= 80 and step >= 300:
                aligner_budget = min(3, team_size - 1)
            return aligner_budget, 0

        # 5+ agents: FASTER early ramp
        if step < 15:  # Was 30
            return 2, 0
        if min_res < 10 and not can_hearts:
            return 1, 0
        elif min_res < 20:  # Was 30
            return 2, 0
        elif min_res < 40:  # Was 50
            return 3, 0
        elif min_res < 80:  # Was 100
            return min(4, team_size - 1), 0
        else:
            return min(team_size - 1, 6), 0


