# ── TV173: TV172 + zone-based stagnation exploration ─────────────────────────

class AlphaTournamentV173AgentPolicy(AlphaTournamentV172AgentPolicy):
    """TournamentV173: TV172 + zone-based exploration during stagnation.

    Instead of all agents exploring the same hub-radius pattern,
    assign each agent a different quadrant based on their team position.
    This reduces overlap and covers more of the map.
    """

    # Quadrant offsets: each agent gets a different quadrant
    _QUADRANT_CENTERS = [
        (18, -18), (-18, -18), (-18, 18), (18, 18),
        (0, -25), (-25, 0), (0, 25), (25, 0),
    ]

    def _stagnation_explore(self, state: MettagridState) -> tuple[Action, str]:
        """Zone-based exploration: each agent explores a different quadrant."""
        hub = self._nearest_hub(state)
        if hub is None:
            return self._explore_action(state, role="aligner", summary="stag_explore")

        # Assign quadrant based on team position
        team_ids = sorted(self._shared_team_ids) if self._shared_team_ids else [self._agent_id]
        try:
            team_pos = team_ids.index(self._agent_id)
        except ValueError:
            team_pos = 0
        quadrant_idx = team_pos % len(self._QUADRANT_CENTERS)
        ox, oy = self._QUADRANT_CENTERS[quadrant_idx]
        target_pos = (hub.global_x + ox, hub.global_y + oy)

        current_pos = _h.absolute_position(state)
        if _h.manhattan(current_pos, target_pos) <= 3:
            # At quadrant center — switch to next quadrant
            quadrant_idx = (quadrant_idx + len(team_ids)) % len(self._QUADRANT_CENTERS)
            ox, oy = self._QUADRANT_CENTERS[quadrant_idx]
            target_pos = (hub.global_x + ox, hub.global_y + oy)

        return self._move_to_position(state, target_pos, summary="stag_zone_explore", vibe="change_vibe_aligner")

    def _aligner_action(self, state: MettagridState) -> tuple[Action, str]:
        step = state.step or self._step_index
        team_id = _h.team_id(state)
        num_agents = len(self._shared_team_ids) if self._shared_team_ids else 8

