        # 5+ agents: same as TV160
        if step < 30:
            return 2, 0
        if min_res < 10 and not can_hearts:
            return 1, 0
        elif min_res < 30:
            return 2, 0
        elif min_res < 50:
            return 3, 0
        elif min_res < 100:
            return min(4, team_size - 1), 0
        else:
            return min(team_size - 1, 6), 0


