# ── TV179: Network-aware scramble targeting ──────────────────────────────

class AlphaTournamentV179AgentPolicy(AlphaTournamentV160AgentPolicy):
    """TournamentV179: TV160 + network-aware scramble targeting.

    Key insight: When idle-scrambling, prioritize enemy junctions that are
    within alignment range of our network. After scrambling, these become
    neutral and immediately alignable, creating faster junction turnover.

    Current scramble scoring uses threat_bonus (near friendly junctions)
    but doesn't check if the scrambled junction would actually be alignable.
    TV179 adds an explicit "alignable_bonus" for junctions within network range.
    """

    def _best_scramble_target(self, state: MettagridState) -> KnownEntity | None:
        """Override to heavily prefer enemy junctions within our alignment network."""
        team_id = _h.team_id(state)
        current_pos = _h.absolute_position(state)
        hub = self._nearest_hub(state)
        neutral_junctions = self._known_junctions(state, predicate=lambda entity: entity.owner in {None, "neutral"})
        friendly_junctions = self._known_junctions(state, predicate=lambda entity: entity.owner == team_id)
        enemy_junctions = self._known_junctions(
            state,
            predicate=lambda entity: entity.owner not in {None, "neutral", team_id},
        )
        if not enemy_junctions:
            return None

        # Build network sources for alignment check
        hubs = self._world_model.entities(entity_type="hub", predicate=lambda entity: entity.team == team_id)
        network_sources = [*hubs, *friendly_junctions]
        hub_position = current_pos if hub is None else hub.position

        def score(entity: KnownEntity) -> tuple[float, float]:
            base_score = _h.scramble_target_score(
                current_position=current_pos,
                hub_position=hub_position,
                candidate=entity,
                neutral_junctions=neutral_junctions,
                friendly_junctions=friendly_junctions,
            )
            # Heavy bonus if this junction would be alignable after scrambling
            alignable_bonus = 0.0
            if _h.within_alignment_network(entity.position, network_sources):
                alignable_bonus = 20.0  # Strong bonus — creates immediate realign opportunity
            return (base_score[0] - alignable_bonus, base_score[1])

        return min(enemy_junctions, key=lambda entity: (score(entity), entity.position))


class AlphaTournamentV179Policy(MettagridSemanticPolicy):
    """TournamentV179: TV160 + network-aware scramble targeting."""
    short_names = ["alpha-tournament-v179"]

    def agent_policy(self, agent_id: int) -> AgentPolicy:
        self._shared_team_ids.add(agent_id)
        if agent_id not in self._agent_policies:
            self._agent_policies[agent_id] = AlphaTournamentV179AgentPolicy(
                self.policy_env_info,
                agent_id=agent_id,
                world_model=SharedWorldModel(),
                shared_claims=self._shared_claims,
                shared_junctions=self._shared_junctions,
                shared_hotspots=self._shared_hotspots,
                shared_team_ids=self._shared_team_ids,
            )
        return self._agent_policies[agent_id]


