# ── TV187: TV186 + 2a mining burst (combine best of v534 + v519 + v522) ──────

class AlphaTournamentV187AgentPolicy(AlphaTournamentV186AgentPolicy):
    """TournamentV187: TV186 + TV178's 2a mining burst.

    Combines all best changes:
    - TV162's lower 6a thresholds (v522 #1 in 6a: 15.75)
    - TV160's faster stagnation for 2a only (v519 #1 in 2a: 13.73)
    - TV178's 2a mining burst first 50 steps (v534 #1 in 4a: 13.40)
    """

    def _pressure_budgets(self, state: MettagridState, *, objective: str | None = None) -> tuple[int, int]:
        step = state.step or self._step_index
        min_res = _h.team_min_resource(state)
        can_hearts = _h.team_can_refill_hearts(state)
        num_agents = self.policy_env_info.num_agents
        team_size = len(self._shared_team_ids) if self._shared_team_ids else num_agents

        if objective == "resource_coverage":
            return 0, 0

        # 2-agent: TV178's mining burst first 50 steps
        if team_size <= 2:
            if step < 50:
                return 1, 0  # 1 aligner + 1 miner for resource buffer
            if not can_hearts and min_res < 7:
                return 1, 0
            return 2, 0

        # 4-agent: EXACT TV142
        if team_size <= 4:
            if step < 50:
                return 1, 0
            if min_res < 7 and not can_hearts:
                return 1, 0
            if min_res < 20:
                return 1, 0
            aligner_budget = 2
            if min_res >= 80 and step >= 300:
                aligner_budget = min(3, team_size - 1)
            return aligner_budget, 0

        # 5+ agents: TV162's lower thresholds
        if step < 30:
            return 2, 0
        if min_res < 10 and not can_hearts:
            return 1, 0
        elif min_res < 25:
            return 2, 0
        elif min_res < 40:
            return 3, 0
        elif min_res < 80:
            return min(4, team_size - 1), 0
        else:
            return min(team_size - 1, 6), 0


