# ── TV207: TV191 + slightly lower 6a thresholds (22/35/70) ───────────────────

class AlphaTournamentV207AgentPolicy(AlphaTournamentV186AgentPolicy):
    """TournamentV207: Slightly faster 6a expansion thresholds.

    TV162: 25/40/80 → v522 6a=15.75 (#1 in 6a)
    TV192: 20/30/60 → v548 6a=13.51 (too aggressive)
    TV207: 22/35/70 → compromise, slightly faster but not too risky
    """

    def _pressure_budgets(self, state: MettagridState, *, objective: str | None = None) -> tuple[int, int]:
        step = state.step or self._step_index
        min_res = _h.team_min_resource(state)
        can_hearts = _h.team_can_refill_hearts(state)
        num_agents = self.policy_env_info.num_agents
        team_size = len(self._shared_team_ids) if self._shared_team_ids else num_agents

        if objective == "resource_coverage":
            return 0, 0

        # 2-agent: EXACT TV142
        if team_size <= 2:
            if not can_hearts and min_res < 7:
                return 1, 0
            return 2, 0

        # 4-agent: TV191 exact (min_res 15)
        if team_size <= 4:
            if step < 50:
                return 1, 0
            if min_res < 7 and not can_hearts:
                return 1, 0
            if min_res < 15:
                return 1, 0
            aligner_budget = 2
            if min_res >= 80 and step >= 300:
                aligner_budget = min(3, team_size - 1)
            return aligner_budget, 0

        # 5+ agents: slightly faster thresholds (22/35/70)
        if step < 30:
            return 2, 0
        if min_res < 10 and not can_hearts:
            return 1, 0
        elif min_res < 22:
            return 2, 0
        elif min_res < 35:
            return 3, 0
        elif min_res < 70:
            return min(4, team_size - 1), 0
        else:
            return min(team_size - 1, 6), 0


