# ── TV215: TV209 + reduce aligners during stagnation ────────────────────────

class AlphaTournamentV215AgentPolicy(AlphaTournamentV209AgentPolicy):
    """TournamentV215: TV209 + reduce aligner budget during stagnation.

    Observation: in stagnation mode (step 800+), 6 aligners scramble each
    other in a zero-sum loop. Both teams decline from peak ~20 to ~10 junctions.

    Hypothesis: reducing to 4 aligners + 4 miners during stagnation builds
    economic advantage. The extra mining lets us sustain more heart refills
    and recover faster from scrambles.
    """

    def _pressure_budgets(self, state: MettagridState, *, objective: str | None = None) -> tuple[int, int]:
        step = state.step or self._step_index
        min_res = _h.team_min_resource(state)
        can_hearts = _h.team_can_refill_hearts(state)
        num_agents = self.policy_env_info.num_agents
        team_size = len(self._shared_team_ids) if self._shared_team_ids else num_agents

        if objective == "resource_coverage":
            return 0, 0

        # 2-agent: EXACT TV142
        if team_size <= 2:
            if not can_hearts and min_res < 7:
                return 1, 0
            return 2, 0

        # 4-agent: TV202 faster ramp (min_res 12)
        if team_size <= 4:
            if step < 50:
                return 1, 0
            if min_res < 7 and not can_hearts:
                return 1, 0
            if min_res < 12:
                return 1, 0
            # In stagnation, reduce to 1 aligner to rebuild economy
            if self._stagnation_mode:
                return 1, 0
            aligner_budget = 2
            if min_res >= 80 and step >= 300:
                aligner_budget = min(3, team_size - 1)
            return aligner_budget, 0

        # 5+ agents: TV207's thresholds + stagnation reduction
        if step < 30:
            return 2, 0
        if min_res < 10 and not can_hearts:
            return 1, 0
        # In stagnation, cap at 4 aligners (6a) to save economy
        if self._stagnation_mode:
            if min_res < 22:
                return 2, 0
            return min(4, team_size - 1), 0
        if min_res < 22:
            return 2, 0
        elif min_res < 35:
            return 3, 0
        elif min_res < 70:
            return min(4, team_size - 1), 0
        else:
            return min(team_size - 1, 6), 0


