# ── TV263: TV259 (#2, TV191+adaptive scramble) + early 3rd aligner (from TV235) ─

class AlphaTournamentV263AgentPolicy(AlphaTournamentV259AgentPolicy):
    """TournamentV263: TV259 (TV191+adaptive scramble) + early 3rd aligner.

    TV259 (v618) = #2 at 14.81. TV235 (v594) showed early 3rd aligner helps.
    Combine: TV191 base + adaptive scramble + early 3rd aligner at step 15.
    """

    def _pressure_budgets(self, state: MettagridState, *, objective: str | None = None) -> tuple[int, int]:
        step = state.step or self._step_index
        min_res = _h.team_min_resource(state)
        can_hearts = _h.team_can_refill_hearts(state)
        num_agents = self.policy_env_info.num_agents
        team_size = len(self._shared_team_ids) if self._shared_team_ids else num_agents

        if objective == "resource_coverage":
            return 0, 0

        if team_size <= 2:
            if not can_hearts and min_res < 7:
                return 1, 0
            return 2, 0

        if team_size <= 4:
            if step < 50:
                return 1, 0
            if min_res < 7 and not can_hearts:
                return 1, 0
            if min_res < 15:
                return 1, 0
            aligner_budget = 2
            if min_res >= 80 and step >= 300:
                aligner_budget = min(3, team_size - 1)
            return aligner_budget, 0

        # 5+ agents: TV162 thresholds + earlier 3rd aligner at step 15
        if step < 15:
            return 2, 0
        if step < 30 and min_res < 20:
            return 2, 0
        if min_res < 10 and not can_hearts:
            return 1, 0
        elif min_res < 25:
            return 2, 0
        elif min_res < 40:
            return 3, 0
        elif min_res < 80:
            return min(4, team_size - 1), 0
        else:
            return min(team_size - 1, 6), 0


