# ── TV266: TV263 (TV259+early aligner) + TV208 stagnation thresholds (22/35/70) ─

class AlphaTournamentV266AgentPolicy(AlphaTournamentV263AgentPolicy):
    """TournamentV266: TV263 + TV208's lower stagnation thresholds.

    TV263 = TV191+adaptive scramble+early aligner (TV162 thresholds: 25/40/80).
    TV208 uses lower: 22/35/70 which helped on that base.
    Try combining on this stronger foundation.
    """

    def _pressure_budgets(self, state: MettagridState, *, objective: str | None = None) -> tuple[int, int]:
        step = state.step or self._step_index
        min_res = _h.team_min_resource(state)
        can_hearts = _h.team_can_refill_hearts(state)
        num_agents = self.policy_env_info.num_agents
        team_size = len(self._shared_team_ids) if self._shared_team_ids else num_agents

        if objective == "resource_coverage":
            return 0, 0

        if team_size <= 2:
            if not can_hearts and min_res < 7:
                return 1, 0
            return 2, 0

        if team_size <= 4:
            if step < 50:
                return 1, 0
            if min_res < 7 and not can_hearts:
                return 1, 0
            if min_res < 15:
                return 1, 0
            aligner_budget = 2
            if min_res >= 80 and step >= 300:
                aligner_budget = min(3, team_size - 1)
            return aligner_budget, 0

        # 5+ agents: TV208 lower thresholds (22/35/70) + early 3rd aligner
        if step < 15:
            return 2, 0
        if step < 30 and min_res < 20:
            return 2, 0
        if min_res < 10 and not can_hearts:
            return 1, 0
        elif min_res < 22:
            return 2, 0
        elif min_res < 35:
            return 3, 0
        elif min_res < 70:
            return min(4, team_size - 1), 0
        else:
            return min(team_size - 1, 6), 0


class AlphaTournamentV266Policy(MettagridSemanticPolicy):
    """TournamentV266: TV263 + TV208 stagnation thresholds."""
    short_names = ["alpha-tournament-v266"]

