# ── TV284: TV272 (#1) + capped 6 aligners (always keep 2 miners) ───────────────

class AlphaTournamentV284AgentPolicy(AlphaTournamentV264AgentPolicy):
    """TournamentV284: TV264 base but max 6 aligners even at high resources.

    TV272 goes to 7 aligners at min_res >= 150 which drops to 1 miner.
    Hypothesis: keeping 2 miners always maintains resource income and
    prevents the economy dips that force aligner count back down.
    Uses lower threshold (50) for 6 aligners to activate it more often.
    """

    def _pressure_budgets(self, state: MettagridState, *, objective: str | None = None) -> tuple[int, int]:
        step = state.step or self._step_index
        min_res = _h.team_min_resource(state)
        can_hearts = _h.team_can_refill_hearts(state)
        num_agents = self.policy_env_info.num_agents
        team_size = len(self._shared_team_ids) if self._shared_team_ids else num_agents

        if objective == "resource_coverage":
            return 0, 0

        if team_size <= 2:
            if not can_hearts and min_res < 7:
                return 1, 0
            return 2, 0

        if team_size <= 4:
            if step < 50:
                return 1, 0
            if min_res < 7 and not can_hearts:
                return 1, 0
            if min_res < 15:
                return 1, 0
            aligner_budget = 2
            if min_res >= 80 and step >= 300:
                aligner_budget = min(3, team_size - 1)
            return aligner_budget, 0

        # 5+ agents: cap at 6 aligners, lower threshold to 50
        if step < 15:
            return 2, 0
        if step < 30 and min_res < 20:
            return 2, 0
        if min_res < 10 and not can_hearts:
            return 1, 0
