# ── TV286: TV272 (#1) + rush 3 aligners from step 0 ────────────────────────────

class AlphaTournamentV286AgentPolicy(AlphaTournamentV272AgentPolicy):
    """TournamentV286: TV272 + rush 3 aligners from step 0 for 5+ agents.

    TV272 starts with 2 aligners until step 15. Hub starts with 24 of each
    resource = enough for 3 aligner kits immediately. Rushing 3 from step 0
    captures junctions sooner.
    """

    def _pressure_budgets(self, state: MettagridState, *, objective: str | None = None) -> tuple[int, int]:
        step = state.step or self._step_index
        min_res = _h.team_min_resource(state)
        can_hearts = _h.team_can_refill_hearts(state)
        num_agents = self.policy_env_info.num_agents
        team_size = len(self._shared_team_ids) if self._shared_team_ids else num_agents

        if objective == "resource_coverage":
            return 0, 0

        if team_size <= 2:
            if not can_hearts and min_res < 7:
                return 1, 0
            return 2, 0

        if team_size <= 4:
            if step < 50:
                return 1, 0
            if min_res < 7 and not can_hearts:
                return 1, 0
            if min_res < 15:
                return 1, 0
            aligner_budget = 2
            if min_res >= 80 and step >= 300:
                aligner_budget = min(3, team_size - 1)
            return aligner_budget, 0

        # 5+ agents: rush 3 from step 0
        if min_res < 10 and not can_hearts:
            return 1, 0
        elif min_res < 22:
            return max(2, 3 if step < 100 else 2), 0
        elif min_res < 35:
            return 3, 0
        elif min_res < 70:
            return min(4, team_size - 1), 0
        elif min_res < 150:
            return min(team_size - 1, 6), 0
        else:
            return min(team_size - 1, 7), 0


