# ── TV322: TV277 + hub-proximity scramble-align cycle ────────────────────────────

class AlphaTournamentV322AgentPolicy(AlphaTournamentV277AgentPolicy):
    """TournamentV322: TV277 + hub-proximity scramble-align cycle.

    Key insight: in late game, all junctions become enemy-owned and aligners
    waste time exploring. Instead, cycle: scramble nearest hub-proximate enemy
    junction → it becomes neutral → align it → hold it → repeat.

    Only scramble enemy junctions within range 25 of hub (alignment range),
    so the junction can be immediately re-aligned after scrambling.
    """

    def _hub_proximate_scramble_target(self, state: MettagridState) -> KnownEntity | None:
        """Find nearest enemy junction within alignment range of hub."""
        team_id = _h.team_id(state)
        current_pos = _h.absolute_position(state)
        hub = self._nearest_hub(state)
        if hub is None:
            return None

        enemy_junctions = self._known_junctions(
            state, predicate=lambda j: j.owner not in {None, "neutral", team_id}
        )
        # Only consider junctions within hub alignment range (25)
        hub_proximate = [
            j for j in enemy_junctions
            if _h.manhattan(hub.position, j.position) <= 25
        ]
        if not hub_proximate:
            return None

        # Prefer nearest to self (minimize travel time)
        return min(hub_proximate, key=lambda j: _h.manhattan(current_pos, j.position))

    def _aligner_action(self, state: MettagridState) -> tuple[Action, str]:
        step = state.step or self._step_index
        team_id = _h.team_id(state)
        num_agents = len(self._shared_team_ids) if self._shared_team_ids else 8

        friendly_count = len(self._known_junctions(
            state, predicate=lambda j: j.owner == team_id
        ))
        enemy_count = len(self._known_junctions(
            state, predicate=lambda j: j.owner not in {None, "neutral", team_id}
        ))

        if friendly_count > self._peak_junction_count:
            self._peak_junction_count = friendly_count
            self._last_junction_growth_step = step
            self._stagnation_mode = False
        else:
            if step - self._last_junction_growth_step > 500:
                self._peak_junction_count = max(
                    friendly_count,
                    self._peak_junction_count - 1
                )
                self._last_junction_growth_step = step

            if num_agents <= 2:
                stag_peak, stag_steps, stag_min_step = 3, 200, 300
            else:
                stag_peak, stag_steps, stag_min_step = 5, 300, 500

            if (self._peak_junction_count >= stag_peak
                    and step - self._last_junction_growth_step > stag_steps
                    and step > stag_min_step):
                self._stagnation_mode = True

        hearts = int(state.self_state.inventory.get("heart", 0))
        hub = self._nearest_hub(state)

        if hearts <= 0:
            self._clear_target_claim()
            self._clear_sticky_target()
            if not _h.team_can_refill_hearts(state):
                return self._miner_action(state, summary_prefix="rebuild_hearts_")
            if hub is not None:
                return self._move_to_known(state, hub, summary="acquire_heart", vibe="change_vibe_heart")
            return self._explore_action(state, role="aligner", summary="find_hub_for_heart")

        if num_agents <= 2 and step < 200:
            pass
        elif step < 200:
            pass
        elif _h.should_batch_hearts(state, role="aligner", hub_position=hub.position if hub else None):
            self._clear_target_claim()
            self._clear_sticky_target()
            assert hub is not None
            return self._move_to_known(state, hub, summary="batch_hearts", vibe="change_vibe_heart")

        target = self._preferred_alignable_neutral_junction(state)
        if target is not None:
            self._claim_target(target.position)
            self._set_sticky_target(target.position, target.entity_type)
            return self._move_to_known(state, target, summary="align_junction", vibe="change_vibe_aligner")

        self._clear_target_claim()
        self._clear_sticky_target()
        if _h.resource_total(state) > 0:
            depot = self._nearest_friendly_depot(state)
            if depot is not None:
                return self._move_to_known(state, depot, summary="deposit_cargo", vibe="change_vibe_aligner")

        current_pos = _h.absolute_position(state)
        hp = int(state.self_state.inventory.get("hp", 0))
        unreachable = self._known_junctions(
            state, predicate=lambda j: j.owner in {None, "neutral"}
        )
        if unreachable:
            safe_unreachable = [
                j for j in unreachable
                if _h.manhattan(current_pos, j.position) < hp - 20
            ]
            targets = safe_unreachable if safe_unreachable else unreachable
            nearest = min(targets, key=lambda j: _h.manhattan(current_pos, j.position))
            dist = _h.manhattan(current_pos, nearest.position)
            if dist < hp - 20:
                return self._move_to_known(state, nearest, summary="expand_toward_junction", vibe="change_vibe_aligner")

        min_res = _h.team_min_resource(state)

        # Hub-proximity scramble cycle: only scramble junctions we can re-align
        if hearts > 0 and min_res >= 7:
            hub_target = self._hub_proximate_scramble_target(state)
            if hub_target is not None:
                return self._move_to_known(state, hub_target, summary="cycle_scramble", vibe="change_vibe_scrambler")

        # Stagnation: explore to find new neutral junctions
        if self._stagnation_mode and hp > 50:
            return self._explore_action(state, role="aligner", summary="stag_find_junction")

        if step % 200 < 100:
            return self._explore_action(state, role="aligner", summary="find_neutral_junction")
        if min_res < 30:
            return self._miner_action(state, summary_prefix="idle_align_")
        return self._explore_action(state, role="aligner", summary="find_neutral_junction")


class AlphaTournamentV322Policy(MettagridSemanticPolicy):
    """TournamentV322: TV277 + hub-proximity scramble-align cycle."""
    short_names = ["alpha-tournament-v322"]
    def agent_policy(self, agent_id: int) -> AgentPolicy:
        self._shared_team_ids.add(agent_id)
        if agent_id not in self._agent_policies:
            self._agent_policies[agent_id] = AlphaTournamentV322AgentPolicy(
                self.policy_env_info, agent_id=agent_id, world_model=SharedWorldModel(),
                shared_claims=self._shared_claims, shared_junctions=self._shared_junctions,
                shared_hotspots=self._shared_hotspots, shared_team_ids=self._shared_team_ids,
            )
        return self._agent_policies[agent_id]


# ── TV323: TV277 + faster 3rd aligner ramp ──────────────────────────────────────

class AlphaTournamentV323AgentPolicy(AlphaTournamentV277AgentPolicy):
    """TournamentV323: TV277 + faster 3rd aligner for 5+ agents.

    TV277 waits for min_res >= 35 for 3rd aligner. Try min_res >= 25 to
    get the 3rd aligner earlier, aligning more junctions before Clips ramps.
    """

    def _pressure_budgets(self, state: MettagridState, *, objective: str | None = None) -> tuple[int, int]:
        step = state.step or self._step_index
        min_res = _h.team_min_resource(state)
        can_hearts = _h.team_can_refill_hearts(state)
        num_agents = self.policy_env_info.num_agents
        team_size = len(self._shared_team_ids) if self._shared_team_ids else num_agents

        if objective == "resource_coverage":
            return 0, 0

        if team_size <= 2:
            if not can_hearts and min_res < 7:
                return 1, 0
            return 2, 0

        if team_size <= 4:
            if step < 50:
                return 1, 0
            if min_res < 7 and not can_hearts:
                return 1, 0
            if min_res < 15:
                return 1, 0
            aligner_budget = 2
            if min_res >= 80 and step >= 300:
                aligner_budget = min(3, team_size - 1)
            return aligner_budget, 0

        # 5+ agents: faster 3rd aligner (25 instead of 35)
        if step < 15:
            return 2, 0
        if step < 30 and min_res < 20:
            return 2, 0
        if min_res < 10 and not can_hearts:
            return 1, 0
        elif min_res < 22:
            return 2, 0
        elif min_res < 25:  # Was 35 in TV277
            return 3, 0
        elif min_res < 60:  # Was 70 in TV277
            return min(4, team_size - 1), 0
        elif min_res < 90:  # Was 100 in TV277
            return min(team_size - 1, 6), 0
        else:
            return min(team_size - 1, 7), 0


class AlphaTournamentV323Policy(MettagridSemanticPolicy):
    """TournamentV323: TV277 + faster 3rd aligner ramp."""
    short_names = ["alpha-tournament-v323"]
    def agent_policy(self, agent_id: int) -> AgentPolicy:
        self._shared_team_ids.add(agent_id)
        if agent_id not in self._agent_policies:
            self._agent_policies[agent_id] = AlphaTournamentV323AgentPolicy(
                self.policy_env_info, agent_id=agent_id, world_model=SharedWorldModel(),
                shared_claims=self._shared_claims, shared_junctions=self._shared_junctions,
                shared_hotspots=self._shared_hotspots, shared_team_ids=self._shared_team_ids,
            )
        return self._agent_policies[agent_id]


# ── TV324: TV322 + TV323 combined ────────────────────────────────────────────────

class AlphaTournamentV324AgentPolicy(AlphaTournamentV322AgentPolicy):
    """TournamentV324: hub-proximity scramble cycle + faster ramp."""

    def _pressure_budgets(self, state: MettagridState, *, objective: str | None = None) -> tuple[int, int]:
        return AlphaTournamentV323AgentPolicy._pressure_budgets(self, state, objective=objective)


